export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

export const THEME_IDS: readonly ThemeId[] = ["t3-dark", "t3-light", "t3-midnight"];

/**
 * Representative color values for each theme surface area.
 * These are used for visual preview swatches in the UI — they are not
 * consumed directly by CSS (which reads from CSS custom properties set on
 * `document.documentElement` via the `data-theme` attribute).
 */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: ThemeId;
  readonly label: string;
  readonly description: string;
  readonly isDark: boolean;
  readonly colors: ThemeColors;
}

export const T3_DARK_THEME: Theme = {
  id: "t3-dark",
  label: "T3 Dark",
  description: "Dark theme with purple accents.",
  isDark: true,
  colors: {
    background: "#0d111a",
    foreground: "#f0f2f7",
    accent: "#7c63e0",
    sidebar: "#0a0e16",
    editor: "#0d111a",
    terminal: "#0a0e16",
    statusBar: "#111827",
  },
};

export const T3_LIGHT_THEME: Theme = {
  id: "t3-light",
  label: "T3 Light",
  description: "Clean light theme with purple accents.",
  isDark: false,
  colors: {
    background: "#ffffff",
    foreground: "#1a2130",
    accent: "#5a3ecc",
    sidebar: "#f5f5f5",
    editor: "#ffffff",
    terminal: "#f8f9fa",
    statusBar: "#e5e7eb",
  },
};

export const T3_MIDNIGHT_THEME: Theme = {
  id: "t3-midnight",
  label: "T3 Midnight",
  description: "Deep blue-black dark theme.",
  isDark: true,
  colors: {
    background: "#080c14",
    foreground: "#c9d4e8",
    accent: "#4f94e8",
    sidebar: "#0c1222",
    editor: "#080c14",
    terminal: "#060a10",
    statusBar: "#0f1926",
  },
};

export const BUILT_IN_THEMES: readonly Theme[] = [
  T3_DARK_THEME,
  T3_LIGHT_THEME,
  T3_MIDNIGHT_THEME,
];

export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

export function isThemeId(value: unknown): value is ThemeId {
  return THEME_IDS.includes(value as ThemeId);
}

export function getThemeById(id: ThemeId): Theme {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) {
    // Fallback to default — should never happen with a valid ThemeId
    return T3_DARK_THEME;
  }
  return theme;
}

