import type { ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

/**
 * Semantic wrapper that subscribes to the theme store, ensuring the theme
 * is applied to the DOM and stays in sync throughout the React lifecycle.
 * Place this near the root of the component tree.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  // Subscribe to theme changes so the hook's useEffect keeps the DOM in sync.
  useTheme();
  return <>{children}</>;
}

