import { BUILT_IN_THEMES, type ThemeId } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

/**
 * Theme selector with color swatch previews for each built-in theme.
 * Renders a radio group of cards — selecting a card applies the theme
 * immediately and persists it to localStorage.
 */
export function ThemeSelector() {
  const { theme: activeThemeId, setTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEMES.map((t) => {
        const selected = activeThemeId === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-start gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id as ThemeId)}
          >
            {/* Color swatch preview */}
            <ThemeSwatch colors={t.colors} />

            {/* Label + description */}
            <span className="flex min-w-0 flex-1 flex-col">
              <span className="text-sm font-medium leading-snug">{t.label}</span>
              <span className="text-xs leading-snug">{t.description}</span>
            </span>

            {selected ? (
              <span className="shrink-0 self-center rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

interface ThemeSwatchProps {
  colors: {
    sidebar: string;
    editor: string;
    accent: string;
    statusBar: string;
  };
}

function ThemeSwatch({ colors }: ThemeSwatchProps) {
  return (
    <span
      className="relative mt-0.5 h-10 w-16 shrink-0 overflow-hidden rounded-md border border-border/50"
      aria-hidden="true"
    >
      {/* Sidebar strip */}
      <span
        className="absolute inset-y-0 left-0 w-4"
        style={{ background: colors.sidebar }}
      />
      {/* Editor area */}
      <span
        className="absolute inset-y-0 right-0"
        style={{ left: "1rem", background: colors.editor }}
      />
      {/* Status bar strip at bottom */}
      <span
        className="absolute inset-x-0 bottom-0 h-2"
        style={{ background: colors.statusBar }}
      />
      {/* Accent dot */}
      <span
        className="absolute right-1.5 top-1.5 h-2 w-2 rounded-full"
        style={{ background: colors.accent }}
      />
    </span>
  );
}

