 1	import { useCallback, useEffect, useSyncExternalStore } from "react";
 2	import { getThemeById, isThemeId, DEFAULT_THEME_ID, type ThemeId } from "@t3tools/shared/theme";
 3	
 4	const STORAGE_KEY = "t3code:theme";
 5	
 6	let listeners: Array<() => void> = [];
 7	let lastThemeId: ThemeId | null = null;
 8	
 9	function emitChange() {
10	  for (const listener of listeners) listener();
11	}
12	
13	function getStored(): ThemeId {
14	  const raw = localStorage.getItem(STORAGE_KEY);
15	
16	  if (isThemeId(raw)) {
17	    return raw;
18	  }
19	
20	  // Migrate from the old light/dark/system values
21	  let migrated: ThemeId;
22	  if (raw === "light") {
23	    migrated = "t3-light";
24	  } else {
25	    // "dark", "system", null, or anything else → t3-dark (safe dark default)
26	    migrated = DEFAULT_THEME_ID;
27	  }
28	  localStorage.setItem(STORAGE_KEY, migrated);
29	  return migrated;
30	}
31	
32	function applyTheme(themeId: ThemeId, suppressTransitions = false) {
33	  if (suppressTransitions) {
34	    document.documentElement.classList.add("no-transitions");
35	  }
36	  document.documentElement.setAttribute("data-theme", themeId);
37	  document.documentElement.classList.toggle("dark", getThemeById(themeId).isDark);
38	  if (suppressTransitions) {
39	    // Force a reflow so the no-transitions class takes effect before removal
40	    // oxlint-disable-next-line no-unused-expressions
41	    document.documentElement.offsetHeight;
42	    requestAnimationFrame(() => {
43	      document.documentElement.classList.remove("no-transitions");
44	    });
45	  }
46	}
47	
48	// Apply immediately on module load to prevent flash
49	applyTheme(getStored());
50	
51	function getSnapshot(): ThemeId {
52	  const themeId = getStored();
53	  if (lastThemeId === themeId) {
54	    return lastThemeId;
55	  }
56	  lastThemeId = themeId;
57	  return lastThemeId;
58	}
59	
60	function subscribe(listener: () => void): () => void {
61	  listeners.push(listener);
62	
63	  // Listen for storage changes from other tabs
64	  const handleStorage = (e: StorageEvent) => {
65	    if (e.key === STORAGE_KEY) {
66	      applyTheme(getStored(), true);
67	      emitChange();
68	    }
69	  };
70	  window.addEventListener("storage", handleStorage);
71	
72	  return () => {
73	    listeners = listeners.filter((l) => l !== listener);
74	    window.removeEventListener("storage", handleStorage);
75	  };
76	}
77	
78	export function useTheme() {
79	  const themeId = useSyncExternalStore(subscribe, getSnapshot);
80	  const theme = getThemeById(themeId);
81	
82	  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";
83	
84	  const setTheme = useCallback((next: ThemeId) => {
85	    localStorage.setItem(STORAGE_KEY, next);
86	    applyTheme(next, true);
87	    emitChange();
88	  }, []);
89	
90	  // Keep DOM in sync on mount/change
91	  useEffect(() => {
92	    applyTheme(themeId);
93	  }, [themeId]);
94	
95	  return { theme: themeId, setTheme, resolvedTheme } as const;
96	}

